from settings.cli import CliOptions
from settings.resolver import resolve


def test_explicit_clear_values_coexist_with_an_unrelated_file_setting():
    cli = CliOptions.parse({"audit": False, "labels": []})
    result = resolve(
        {"workers": 10, "audit": True, "labels": ["inherited"]}, cli
    )

    assert result == {
        "workers": 10,
        "audit": False,
        "labels": [],
    }
